WD=[-22, 22, 13, -26, 28, 10, 32, -15, -33, 24, 3, 30, 18, -18, -11, 48, -22, 38, -2, 27, 16, -23, -23, 6, 0, 21, -9, -3, 6, -49, 8, 0, 13, -127, -32, -23, -34, 81, -32, -86, 10, -11, -5, -20, 22, 34, -29, -28, 6, -42, -5, -12, 31, 28, 10, -5, 0, 49, -10, 0, 27, -19, -21, 41, -3, 8, 44, -23, 10, 25, 38, 0, -7, 52, 9, 0, 17, -65, 10, 42, -11, 61, -12, -7, 39, -21, 0, 20, 10, 14, -25, -9, -8, -9, 5, 19, -40, 45, 4, 23, 15, 0, 4, 49, 23, -47, 46, 15, 0, 0, -46, -36, -4, 9, 15, 27, 16, -25, -4, 0, -12, 10, -9, -21, 0, -11, -51, 52]
